import { z } from "zod";
const optionalString = z.preprocess((value) => typeof value === "string" && value.trim() === "" ? undefined : value, z.string().optional());
const optionalEmail = z.preprocess((value) => typeof value === "string" && value.trim() === "" ? undefined : value, z.string().email().optional());
const optionalUrl = z.preprocess((value) => typeof value === "string" && value.trim() === "" ? undefined : value, z.string().url().optional());
export const EnvSchema = z.object({
    NODE_ENV: z
        .enum(["development", "production", "test"])
        .default("development"),
    PORT: z.coerce.number().default(4000),
    LOG_LEVEL: optionalString,
    FRONTEND_URL: optionalString,
    JWT_SECRET: z.string().min(32, "JWT_SECRET must be at least 32 characters"),
    DATABASE_PATH: optionalString,
    DATABASE_URL: optionalString,
    REQUIRE_POSTGRES: optionalString,
    DB_USER: optionalString,
    DB_PASSWORD: optionalString,
    DB_HOST: optionalString,
    DB_PORT: z.coerce.number().optional(),
    DB_NAME: optionalString,
    REDIS_URL: optionalString,
    REQUIRE_REDIS: optionalString,
    REDIS_HOST: optionalString,
    REDIS_PORT: z.coerce.number().optional(),
    S3_BUCKET: optionalString,
    S3_REGION: z.string().default("us-east-1"),
    S3_ENDPOINT: optionalString,
    S3_ACCESS_KEY_ID: optionalString,
    S3_SECRET_ACCESS_KEY: optionalString,
    S3_PUBLIC_URL: optionalString,
    RESEND_API_KEY: optionalString,
    BREVO_API_KEY: optionalString,
    BREVO_SENDER_EMAIL: optionalEmail,
    BREVO_SENDER_NAME: optionalString,
    DEFAULT_NOTIFICATION_EMAIL: optionalEmail,
    RATE_LIMIT_WINDOW_MS: z.coerce.number().optional(),
    RATE_LIMIT_MAX_REQUESTS: z.coerce.number().optional(),
    RATE_LIMIT_SKIP_LOCALHOST: optionalString,
    NOTIFICATION_FROM_EMAIL: optionalString,
    NOTIFICATION_TEAM_EMAILS: optionalString,
    NOTIFICATION_TEAM_PHONES: optionalString,
    NOTIFICATION_TEAM_WHATSAPP_NUMBERS: optionalString,
    TWILIO_ACCOUNT_SID: optionalString,
    TWILIO_AUTH_TOKEN: optionalString,
    TWILIO_SMS_FROM: optionalString,
    TWILIO_WHATSAPP_FROM: optionalString,
    SHE_TEAM_EMAILS: optionalString,
    SHE_TEAM_PHONES: optionalString,
    SHE_TEAM_WHATSAPP_NUMBERS: optionalString,
    GOOGLE_DOCS_EXPORT_BASE_URL: optionalString,
    SMTP_HOST: optionalString,
    SMTP_PORT: z.coerce.number().optional(),
    SMTP_SECURE: optionalString,
    SMTP_USER: optionalString,
    SMTP_PASS: optionalString,
    SMTP_FROM: optionalString,
    TWILIO_SID: optionalString,
    TWILIO_FROM: optionalString,
    SENTRY_DSN: optionalString,
    AI_API_BASE_URL: optionalUrl,
    AI_MODEL: optionalString,
    OPENAI_API_KEY: optionalString,
    AI_API_KEY: optionalString,
});
